"use client";

import { useMemo } from "react";
import styles from "../../workspace.module.css";
import { FamilyTree } from "../../sections/FamilyTree";
import { PersonSpotlight } from "../../sections/PersonSpotlight";
import { WorkspaceEmptyState } from "../../sections/WorkspaceEmptyState";
import { useTenantWorkspaceData } from "../../useTenantWorkspaceData";
import { QuickAddRelative } from "./QuickAddRelative";
import { FamilyWorkspaceShell } from "../../sections/FamilyWorkspaceShell";

type MemberProfileWorkspaceProps = {
  personId: string;
};

export function MemberProfileWorkspace({ personId }: MemberProfileWorkspaceProps) {
  const {
    session,
    activeWorkspaceId,
    families,
    people,
    relationships,
    selectedPersonId,
    setSelectedPersonId,
    refresh,
    loading,
    message,
  } = useTenantWorkspaceData(personId);

  const selectedFamily = families.find((family) => family.id === activeWorkspaceId) ?? null;
  const selectedPerson = people.find((person) => person.id === selectedPersonId) ?? null;
  const activeMembership = useMemo(
    () => session?.memberships.find((membership) => membership.familyId === activeWorkspaceId) ?? null,
    [session, activeWorkspaceId],
  );

  if (loading) {
    return (
      <WorkspaceEmptyState
        title="Loading member profile"
        message="We are gathering the family member record and their relationship context."
      />
    );
  }

  if (!session || !selectedFamily || !selectedPerson) {
    return (
      <WorkspaceEmptyState
        title="Member profile not ready"
        message={message || "This family member could not be loaded in the active workspace."}
      />
    );
  }

  return (
    <FamilyWorkspaceShell
      session={session}
      families={families}
      activeWorkspaceId={activeWorkspaceId}
      selectedFamily={selectedFamily}
      people={people}
      selectedPerson={selectedPerson}
      pageTitle={selectedPerson.fullName}
      pageSubtitle="Explore this person&apos;s profile, family context, and connected branches in the tree."
      activeView="profile"
      canManageData={activeMembership?.role === "admin" || activeMembership?.role === "editor"}
      onSwitchFamily={(familyId) => {
        void fetch("/api/auth/active-workspace", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ familyId }),
        }).then(() => window.location.assign("/family-space"));
      }}
      rightRail={<PersonSpotlight person={selectedPerson} people={people} relationships={relationships} compact />}
    >
      <div className={styles.feedStack}>
        <FamilyTree
          people={people}
          relationships={relationships}
          selectedPersonId={selectedPerson.id}
          onSelectPerson={setSelectedPersonId}
          memberCount={people.length}
          relationshipCount={relationships.length}
        />
        <QuickAddRelative
          familyId={selectedFamily.id}
          anchorPerson={selectedPerson}
          relationships={relationships}
          canEdit={activeMembership?.role === "admin" || activeMembership?.role === "editor"}
          onCreated={refresh}
        />
      </div>
    </FamilyWorkspaceShell>
  );
}
